select
	SELLER_MAINCODE as iin_bin,
    CUSTOMER_MAINCODE as iin_bin_pokup,
    SELLER_MAINCODE as iin_bin_prod,
    toDate(DATE_OPER) as date,
    concat('ЕИАС') as database,
    concat('Транспортные средства') as aktivy,
    concat('Приобретение') as oper,
    concat(coalesce(CFM_TYPE,''),', ',coalesce(CFM_NAME, ''),', ',dopinfo,'; Покупатель: ', CUSTOMER_MAINCODE,';') as dopinfo,
    concat('') as num_doc,
    toInt64(OPER_TENGE_AMOUNT as int) as summ

from (



select
    distinct
    MESS_ID,
    OPER_IDVIEW,
    OPER_TENGE_AMOUNT,
    OPER_NUMBER,
    DATE_OPER,
    dopinfo,
    CUSTOMER_MAINCODE,
    SELLER_MAINCODE,
    CFM_TYPE,
    CFM_NAME
from pfr_dashboard.asloy_joined_table where DATE_OPER>='2023-01-01' and DATE_OPER<= '2024-12-31'


and not(MESS_REASON_CODE='12' or MESS_REASON_CODE='13' or MESS_REASON_CODE='14' or MESS_OPER_STATUS_CODE='2' or MESS_OPER_STATUS_CODE='3') and

SELLER_MAINCODE  in (select IIN from ids) and CUSTOMER_MAINCODE is not null and CUSTOMER_MAINCODE!='' and


 (
     match(lowerUTF8(dopinfo), 'автомобил.*vin|электромобил.*vin|машина.*(легковая|грузовая|дорожная|снегоубор|снегоуплотнитель|бортовая|заливочная|шасси|крановая|буровая|транспорт|уборочная|зерноупак|вакуумная|дождевальная|бронированная|доставочная|бетоноотдел|посадочная|илососная|подъемник|ледозаливочная|мусоровоз|комбинированная)*.шасси')
     or match(lowerUTF8(dopinfo), '(автобус|джип|фронтальный погрузчик|фургон|электропогрузчик|погрузчик|авто|бетоносмеситель|тягач седельный|тягач|каток|прицеп|самосвал|экскаватор|трал|внедорожник|минивэн|бульдозер|уборочный комбайн|гидроцикл|мотоцикл|электроцикл).vin')
     or match(lowerUTF8(dopinfo), '(автобус|джип|фронтальный погрузчик|фургон|электропогрузчик|погрузчик|авто|бетоносмеситель|тягач седельный|тягач|каток|прицеп|самосвал|экскаватор|трал|внедорожник|минивэн|бульдозер|уборочный комбайн|гидроцикл|мотоцикл|электроцикл).шасси')
     or match(lowerUTF8(dopinfo), '(aston martin|audi|bentley|bmw|bugatti|cadillac|chevrolet|chrysler|citroen|dodge|ferrari|fiat|ford|honda|hyundai|infiniti|jaguar|jeep|kia|koenigsegg|lamborghini|land rover|lincoln|maserati|mclaren|mazda|mini|mitsubishi|nissan|opel|peugeot|porsche|renault|rolls royce|skoda|subaru|tesla|toyota|volkswagen|volvo).*vin')
     or match(lowerUTF8(dopinfo), 'мотоцикл.*(harley davidson|ducati|yamaha|suzuki|kawasaki|honda|bmw|triumph|indian motorcycle|victory motorcycle|moto guzzi|aprilia|ktm|benelli|cz|peugeot motorcycles|yamaha motorcycles|suzuki motorcycles|honda motorcycles|bimota|mv agusta|norton motorcycles|lambretta|vespa|rizoma|buell|moto morini|zongshen|cfmoto|sherco|gasgas|beta motorcycles).*vin')
     or match(lowerUTF8(dopinfo), 'вертолет.*(bell helicopters|boeing helicopters|airbus helicopters|sikorsky helicopters|russian helicopters|robson helicopter|agusta westland|kamov|kawasaki helicopters|enstrom helicopters|pzl świdnik|eurocopter|sh-60 sea hawk|mi-8|mi-24|mi-28|ka-52|ka-226|uh-60 black hawk|ec-135|ec-145|ch-47 chinook|apache helicopter|h225 super puma|as350 ecureuil|hughes 500|robinson helicopter|kaman sh-2 seasprite|agusta a109|boeing ah-64 apache)')

)


      AND NOT

    (match(lowerUTF8(dopinfo), 'ковры|мармелад|футболка|аккумулятор|решетка|моторн.*масл|трансмиссион|стекло|жидкость|шарова|отогрев|оппресовка|оклейка|диагностика|снятие|чехол|чехлов|полировка|смазка|серьг|передн|задн|левый|правый|лева|права|пошив|помпа|насос|ступиц|лентблок|ленблок|клапан|на авто|стол|рейка|реставрац|обводной|ремень|пыльник|проставка|прокладка|катушка|лампа|фара|диск|генератор|криминалист|молдинг|рычаг|брелок|лобов|тониров|тент|для авто|фара|мини|lego|1:6|1:7|1:64|1:9|1:8|1:12|1:16|1:24|1:32|гонщик|химчистка|упаковк|коробка|мойка|радио|коврик|шумоизоляци|брызговик|уборка|обслуживан|хранени|вознагражд|комисси|замен|сайт|редуктор|этикет|игруш|циклон|лизинг|реклам|тур|эксплуат|жөндеу|жаңарту|жолын|амортиз|фильтр|транспортиров|парфюм|резец|детал|тест|жұмыс|test|полет|мастерск|подшиппн|пользовани|оборудов|шкаф|конструк|монтаж|маршрут|отчет|установ|фасад|финанс|толкат|подшипник|штабел|провод|свеч|подготов|полет|осмотр|запчаст|зап.*час|кресл|систем|фото|станок|манипул|комплект|форсун|ассенизатор|масло|тех|ремонт|оказан|выполн|арен|услуг|работ|рейс|ролик|капот|возмещен|допол|изготовлен|затирк|покраск|перевозк|организаци|мероприят|сцеплени|набор|комплект|плит|смена|ускорит|участ|проведен')
    or
    lowerUTF8(dopinfo) LIKE 'двигатель%' or
    lowerUTF8(dopinfo) LIKE 'шин%' or
    lowerUTF8(dopinfo) LIKE 'автошин%' or
    lowerUTF8(dopinfo) LIKE 'насос%' or
    lowerUTF8(dopinfo) LIKE 'кондиц%' or
    lowerUTF8(dopinfo) LIKE 'ламинир%' or
    lowerUTF8(dopinfo) LIKE 'стекл%' or
    lowerUTF8(dopinfo) LIKE 'фасад%' or
    lowerUTF8(dopinfo) LIKE 'аккумулятор%' or
    lowerUTF8(dopinfo) LIKE 'дизел%' or
    lowerUTF8(dopinfo) LIKE 'стойк%' or
    lowerUTF8(dopinfo) LIKE 'радиатор%' or
    lowerUTF8(dopinfo) LIKE 'сбор%'))
) AS subquery
WHERE iin_bin = '$P-IIN'
AND date BETWEEN '$P-DATEFROM' AND '$P-DATETO';